using Dapper;
using Valora.Application.Contracts;
using Valora.Application.DTOs;
using Valora.Infrastructure.Database;

namespace Valora.Infrastructure.Repositories;
public sealed class SurveyRepository(IDbConnectionFactory f):ISurveyRepository,IResponseRepository{
 public async Task<dynamic?> GetPublicByTokenAsync(string token){using var c=f.Create(); return await c.QuerySingleOrDefaultAsync("SELECT s.id,s.organization_id,s.form_id,s.title,s.description,s.status,s.expires_at,o.public_name AS organization_name FROM valorapesquisa.surveys s JOIN valorapesquisa.organizations o ON o.id=s.organization_id WHERE s.token_hash=@token AND s.is_deleted=false AND s.status IN ('active','published','open') AND (s.expires_at IS NULL OR s.expires_at>now())",new{token});}
 public async Task<Guid> SaveResponseAsync(Guid surveyId,SubmitResponseRequest r){using var c=f.Create(); c.Open(); using var tx=c.BeginTransaction(); try{ var s=await c.QuerySingleAsync<dynamic>("SELECT organization_id,form_id FROM valorapesquisa.surveys WHERE id=@surveyId AND is_deleted=false",new{surveyId},tx); var resultToken=$"result_{Guid.NewGuid():N}"; var id=await c.ExecuteScalarAsync<Guid>("INSERT INTO valorapesquisa.responses(organization_id,survey_id,form_id,participant_name,participant_email,result_token_hash,completed_at) VALUES (@organization_id,@surveyId,@form_id,@ParticipantName,@ParticipantEmail,@resultToken,now()) RETURNING id",new{s.organization_id,s.form_id,surveyId,r.ParticipantName,r.ParticipantEmail,resultToken},tx); var questions=(await c.QueryAsync<dynamic>("SELECT id,dimension_id,display_order FROM valorapesquisa.questions WHERE form_id=@form_id AND is_deleted=false ORDER BY display_order",new{s.form_id},tx)).ToList(); decimal total=0; var dimensionTotals=new Dictionary<Guid,decimal>(); foreach(var q in questions){ var key=((Guid)q.id).ToString(); object? raw=null; if(r.Answers is not null && (!r.Answers.TryGetValue(key,out raw))) r.Answers.TryGetValue($"q{(int)q.display_order}",out raw); var score=raw is null?0:Math.Clamp(Convert.ToDecimal(raw),0,5); total+=score; var dim=(Guid)q.dimension_id; dimensionTotals[dim]=dimensionTotals.GetValueOrDefault(dim)+score; await c.ExecuteAsync("INSERT INTO valorapesquisa.response_answers(response_id,question_id,answer_json,answer_text,score,max_score) VALUES (@id,@questionId,jsonb_build_object('value',@raw),@text,@score,5)",new{id,questionId=(Guid)q.id,raw=raw?.ToString(),text=raw?.ToString(),score},tx); } var label=total switch { >=25 and <=55=>"Crítico", >=56 and <=85=>"Em estruturação", >=86 and <=110=>"Estruturada", >=111=>"Alta maturidade", _=>"Crítico"}; await c.ExecuteAsync("INSERT INTO valorapesquisa.result_scores(organization_id,response_id,total_score,max_score,percentage,maturity_label,strategic_truth,devolutiva_json) VALUES (@organizationId,@id,@total,125,@percentage,@label,@truth,jsonb_build_object('source','api-postgresql'))",new{organizationId=(Guid)s.organization_id,id,total,percentage=Math.Round(total/125*100,2),label,truth="Resultado calculado pela API ASP.NET Core/PostgreSQL."},tx); foreach(var dt in dimensionTotals){ var name=await c.ExecuteScalarAsync<string>("SELECT name FROM valorapesquisa.form_dimensions WHERE id=@id",new{id=dt.Key},tx); await c.ExecuteAsync("INSERT INTO valorapesquisa.dimension_scores(organization_id,response_id,dimension_name,score,max_score,percentage,level_label) VALUES (@organizationId,@responseId,@name,@score,25,@percentage,@label)",new{organizationId=(Guid)s.organization_id,responseId=id,name,score=dt.Value,percentage=Math.Round(dt.Value/25*100,2),label},tx); } var code=$"VAL-{id:N}"[..14]; await c.ExecuteAsync("INSERT INTO valorapesquisa.certificates(organization_id,response_id,certificate_code,participant_name,issuer_name,survey_name,score_label,maturity_label) VALUES (@organizationId,@id,@code,@ParticipantName,'Valora Pulse™','Diagnóstico Valora Insight™',@scoreLabel,@label)",new{organizationId=(Guid)s.organization_id,id,code,r.ParticipantName,scoreLabel=$"{total}/125",label},tx); if(!string.IsNullOrWhiteSpace(r.ParticipantEmail)) { await c.ExecuteAsync("INSERT INTO valorapesquisa.email_jobs(organization_id,response_id,recipient_email,subject,template_key,status,payload_json) VALUES (@organizationId,@id,@ParticipantEmail,'Valora Insight™ - Seu diagnóstico está pronto','result-ready','pending',jsonb_build_object('score',@total,'level',@label))",new{organizationId=(Guid)s.organization_id,id,r.ParticipantEmail,total,label},tx); await c.ExecuteAsync("INSERT INTO valorapesquisa.communications(organization_id,survey_id,response_id,channel,event_type,status,recipient_masked) VALUES (@organizationId,@surveyId,@id,'email','result-ready','pending',@masked)",new{organizationId=(Guid)s.organization_id,surveyId,id,masked=r.ParticipantEmail},tx); } tx.Commit(); return id;} catch{tx.Rollback(); throw;} }
 public async Task<dynamic?> GetResultAsync(Guid responseId){using var c=f.Create(); return await c.QuerySingleOrDefaultAsync("SELECT r.id,r.participant_name,rs.total_score AS TotalScore,rs.percentage,rs.maturity_label AS Level,c.certificate_code AS ValidationCode FROM valorapesquisa.responses r LEFT JOIN valorapesquisa.result_scores rs ON rs.response_id=r.id LEFT JOIN valorapesquisa.certificates c ON c.response_id=r.id WHERE r.id=@responseId",new{responseId});}
 public async Task<int> CountActiveSurveysAsync(Guid organizationId){using var c=f.Create(); return await c.ExecuteScalarAsync<int>("SELECT count(*) FROM valorapesquisa.surveys WHERE organization_id=@organizationId AND status='active' AND is_deleted=false",new{organizationId});} public async Task<int> CountResponsesThisMonthAsync(Guid organizationId){using var c=f.Create(); return await c.ExecuteScalarAsync<int>("SELECT count(*) FROM valorapesquisa.responses WHERE organization_id=@organizationId AND created_at >= date_trunc('month', now()) AND is_deleted=false",new{organizationId});}}
